from __future__ import annotations
from pydantic import BaseModel, Field, field_validator, model_validator, ConfigDict
from typing import Literal

class ResearchFinding(BaseModel):
    model_config = ConfigDict(
        strict=False,       # allow coercion (e.g. "0.9" -> 0.9)
        extra="forbid",     # reject unexpected fields from the LLM
        populate_by_name=True,
    )

    title: str = Field(..., min_length=3, max_length=200,
                       description="Concise title of the finding")
    summary: str = Field(..., min_length=10,
                         description="1-3 sentence summary")
    confidence: float = Field(..., ge=0.0, le=1.0,
                              description="Confidence score between 0 and 1")
    category: Literal["technical", "business", "legal", "other"]
    sources: list[str] = Field(default_factory=list)

    @field_validator("title")
    @classmethod
    def title_not_generic(cls, v: str) -> str:
        if v.strip().lower() in {"finding", "result", "summary", "output"}:
            raise ValueError(f"Title '{v}' is too generic; provide a specific title")
        return v.strip()

    @model_validator(mode="after")
    def high_confidence_needs_sources(self) -> ResearchFinding:
        if self.confidence > 0.8 and not self.sources:
            raise ValueError("High-confidence findings must include at least one source")
        return self

from __future__ import annotations
from pydantic import BaseModel, Field, field_validator, model_validator, ConfigDict
from typing import Optional
from datetime import date
from enum import Enum
import json, re, logging
import anthropic

logger = logging.getLogger(__name__)

class CaseType(str, Enum):
    CIVIL = "civil"
    CRIMINAL = "criminal"
    ADMINISTRATIVE = "administrative"
    BANKRUPTCY = "bankruptcy"

class Party(BaseModel):
    name: str = Field(..., min_length=2)
    role: str  # 'plaintiff', 'defendant', etc.

class CourtDecision(BaseModel):
    model_config = ConfigDict(extra="forbid", strict=False)

    case_number: str = Field(..., pattern=r"^\d{2}-[A-Z]{2}-\d{4,6}$")
    case_type: CaseType
    filing_date: date
    decision_date: Optional[date] = None
    court: str = Field(..., min_length=5)
    jurisdiction: str  # two-letter state code or 'FED'
    parties: list[Party] = Field(..., min_length=2)
    outcome: Optional[str] = None
    damages_usd: Optional[float] = Field(None, ge=0)
    summary: str = Field(..., min_length=50, max_length=2000)

    @field_validator("jurisdiction")
    @classmethod
    def valid_jurisdiction(cls, v: str) -> str:
        valid = {
            "AL","AK","AZ","AR","CA","CO","CT","DE","FL","GA","HI","ID","IL","IN",
            "IA","KS","KY","LA","ME","MD","MA","MI","MN","MS","MO","MT","NE","NV",
            "NH","NJ","NM","NY","NC","ND","OH","OK","OR","PA","RI","SC","SD","TN",
            "TX","UT","VT","VA","WA","WV","WI","WY","FED"
        }
        if v.upper() not in valid:
            raise ValueError(f"Unknown jurisdiction '{v}'")
        return v.upper()

    @model_validator(mode="after")
    def decision_after_filing(self) -> CourtDecision:
        if self.decision_date and self.filing_date:
            if self.decision_date < self.filing_date:
                raise ValueError("decision_date cannot precede filing_date")
        return self

_client = anthropic.Anthropic()
_SCHEMA = json.dumps(CourtDecision.model_json_schema(), indent=2)
_SYSTEM = f"You are a legal document parser. Return ONLY JSON matching:\n{_SCHEMA}"

def extract_decision(text: str, doc_id: str) -> CourtDecision:
    messages = [{"role": "user", "content": text[:40000]}]
    last_err: str | None = None
    for attempt in range(3):
        if last_err:
            messages.append({"role": "assistant", "content": "<previous>"})
            messages.append({"role": "user",
                             "content": f"Validation failed:\n{last_err}\nReturn corrected JSON."})
        resp = _client.messages.create(
            model="claude-opus-4-5", max_tokens=2048,
            system=_SYSTEM, messages=messages,
        )
        raw = resp.content[0].text.strip()
        try:
            data = json.loads(re.sub(r"^```(?:json)?|```$", "", raw, flags=re.M))
            return CourtDecision.model_validate(data)
        except Exception as e:
            last_err = str(e)
            logger.warning("doc=%s attempt=%d err=%s", doc_id, attempt, last_err)
    raise RuntimeError(f"Extraction failed for {doc_id} after 3 attempts")

